var ClientTaskInfo = Class.create();
ClientTaskInfo.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	// STRY0082087, STRY0083025, STRY0083027
	getMembersAndOUsForRestrictedGroup: function()
	{
		var taskerHelpers = new TaskerHelpers();
		var MembersAndOUsForRestrictedGroup = {};
		var newRestrictedGroupId = this.getParameter('newRestrictedGroupId');
		var previousRestrictedGroupId = this.getParameter('previousRestrictedGroupId');
		var formValues = JSON.parse(this.getParameter('formValues'));
		var formLabels = JSON.parse(this.getParameter('formLabels'));
		var restrictedGroupOUs = taskerHelpers.getOUsForRestrictedGroupIdAbbrevName(newRestrictedGroupId);
		var restrictedGroupMembers = taskerHelpers.getMembersForRestrictedGroupIdNameEmailUserId(newRestrictedGroupId);
		var returnFormValues = taskerHelpers.getTaskerFormDisplayValues(formValues);

		MembersAndOUsForRestrictedGroup.newRestrictedGroupId = newRestrictedGroupId;
		MembersAndOUsForRestrictedGroup.newRestrictedGroupName = restrictedGroupMembers.groupName;
		MembersAndOUsForRestrictedGroup.previousRestrictedGroupId = previousRestrictedGroupId;
		MembersAndOUsForRestrictedGroup.restrictedGroupOUs = restrictedGroupOUs;
		MembersAndOUsForRestrictedGroup.restrictedGroupMembers = restrictedGroupMembers;
		MembersAndOUsForRestrictedGroup.returnFormValues = returnFormValues;
		MembersAndOUsForRestrictedGroup.formLabels = formLabels;

		MembersAndOUsForRestrictedGroup = taskerHelpers.evaluateRestrictedGroupForForm(MembersAndOUsForRestrictedGroup);
		var answer = JSON.stringify(MembersAndOUsForRestrictedGroup);
		return answer;
	},

	// v2.5 P2 | 08.24.2020 | STRY0077855 - STRY0077847 : Suspense Date Timing Updates
	compareTaskSuspenseDateToParentAndChildDates: function(){
		var data = {};
		var taskSuspenseDateOlderThanParent = false;
		var subtaskSuspenseDateOlderThanParent = false;
		var task_id = this.getParameter('sysparm_task_id');
		var parent_task_id = this.getParameter('sysparm_parent_task_id');
		var taskNewSuspenseDate = this.getParameter('sysparm_taskNewSuspenseDate');
		// STRY0091972
		var dteTaskNewSuspenseDate = new GlideDateTime();
		dteTaskNewSuspenseDate.setDisplayValue(taskNewSuspenseDate);
		var numTaskNewSuspenseDate = dteTaskNewSuspenseDate.getNumericValue();

		var grParentTask = new GlideRecord('x_153465_discovert_route_task_instance');
		if(grParentTask.get(parent_task_id)){
			var gdt2 = new GlideDateTime(grParentTask.suspense_date);
			var gdtParent = gdt2.getNumericValue();
			// STRY0091972
			if(numTaskNewSuspenseDate > gdtParent){
				taskSuspenseDateOlderThanParent = true;
			}
		}

		if(task_id != '-1'){
			var countDateSubtasks = new GlideRecord('x_153465_discovert_route_task_instance');
			countDateSubtasks.addQuery('parent', task_id);
			// STRY0091972
			countDateSubtasks.addQuery('suspense_date','>', dteTaskNewSuspenseDate); 
			countDateSubtasks.addNotNullQuery('suspense_date');
			countDateSubtasks.addQuery('state', "NOT IN", "3,4,7");
			countDateSubtasks.query();
			if(countDateSubtasks.next()){
				subtaskSuspenseDateOlderThanParent = true;
			}
		}
		data.subtaskSuspenseDateOlderThanParent = subtaskSuspenseDateOlderThanParent;
		data.taskSuspenseDateOlderThanParent = taskSuspenseDateOlderThanParent;
		return JSON.stringify(data);
	},

    // v2.5.13 | 08.12.2020 | STRY0076619:  Sequential Review
	checkActiveOrderOfParent: function(){
		var taskOrderNeedsToBeHiger=false;
		var task_parent_id = this.getParameter('sysparm_task_parent');
		var order_setting = this.getParameter('sysparm_order');
		var grTaskParent = new GlideRecord('x_153465_discovert_route_task_instance');
		if(grTaskParent.get(task_parent_id)){
			// start assuming true
			var taskOrderSelectedIsAlreadyCompleted = true;
			var grSubTasksActiveLower = new GlideRecord('x_153465_discovert_route_task_instance');
			grSubTasksActiveLower.addQuery('parent', task_parent_id);
			grSubTasksActiveLower.addQuery('active', true);
			grSubTasksActiveLower.addQuery('task_order', '<=', order_setting);
			grSubTasksActiveLower.query();
			while (grSubTasksActiveLower.next()){
				taskOrderSelectedIsAlreadyCompleted = false;
				break;
			}
			taskOrderNeedsToBeHiger = taskOrderSelectedIsAlreadyCompleted;
		}
		return taskOrderNeedsToBeHiger;
	},


	// KT - STRY0058367:  2.2 PATCH 6 - FEB-26-2020
	/*
	As a "Task Owner" or "Assigned Member" of a parent task, upon filling out the new sub task form, The "Task Owner" field on the new sub task form should default to:
	• If parent task is unassigned: the Task Parent Originator (Created by field)
	• If parent task is assigned: the Task Parent Assigned Member
 	*/
	setSubTaskTaskOwner: function(){

		var task_owner = "";
		var parent_sys_id = this.getParameter('sysparm_parent');

		var grTaskParent = new GlideRecord('x_153465_discovert_route_task_instance');
		grTaskParent.addQuery("sys_id",parent_sys_id);
		grTaskParent.query();

		if (grTaskParent.next()) {

			if(grTaskParent.state == "-5" || grTaskParent.getValue('assigned_to') == null){ //Unassigned
				// STRY0078378 - if task owner of parent not set, set the owner of the subtask to the originator of the parent
				if (grTaskParent.getValue('u_task_requester') == null){
					task_owner = grTaskParent.getValue('originator');	
				} else {
					task_owner = grTaskParent.getValue('u_task_requester');	
				}

			}

			if(grTaskParent.state == "1" || grTaskParent.getValue('assigned_to') != null){ //Assigned
				task_owner = grTaskParent.getValue('assigned_to');
			}
		}

		return task_owner;
	},

	// KT - STRY0048914:  2.2 PATCH 6 - FEB-26-2020
	/*
	As a user that can create subtasks, Parent Task Owner or Parent Assigned Member, upon filling out the new sub task form, I want the "instruction" field to be EDITABLE when it is in a "new" state, so that I can provide updated Instructions to the assigned member of the sub task. 
	*/
	checkUserIsAssignedMemberORTaskOwner: function(){

		var UserIsAssignedMemberORTaskOwner = false;
		var currentUser = gs.getUser();
		var parent_sys_id = this.getParameter('sysparm_parent');

		var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
		grTask.addQuery("sys_id",parent_sys_id);
		grTask.query();

		while(grTask.next()){
			if(grTask.assigned_to == currentUser.getID() || grTask.u_task_requester == currentUser.getID()){
				UserIsAssignedMemberORTaskOwner = true;
			}
			return UserIsAssignedMemberORTaskOwner;
		}
	},

	//MK-STRY0052581
	updateTaskStateToComplete: function(){
		var task_sysID = (this.getParameter('sysparm_sysId'));
		var set_state = new GlideRecord("x_153465_discovert_route_task_instance");
		if(set_state.get(task_sysID)){
			set_state.state = 3;
			set_state.work_notes = 'Task was marked as Read';
			set_state.update();
		}
	},

	taskParentHasSubtasks: function(){
		var parentID = this.getParameter("parentID");
		var data ;
		var gr = new GlideRecord('x_153465_discovert_route_task_instance');
		gr.addQuery('sys_id',parentID);
		gr.query();

		while(gr.next()){
			data = gr.calchaschildren;
		}
		return data;
	},

